export default Object.entries(questionSets).flatMap(([topicId, questions]) =>
  questions.map(([suffix, question, options, correctAnswerIndex, shortExplanation, fullExplanation, difficulty]) => ({
    id: `${prefixes[topicId]}_${suffix}`,
    topicId,
    question,
    options,
    correctAnswerIndex,
    shortExplanation,
    fullExplanation,
    difficulty
  }))
);
